    right[n-1] = nums[n-1];
    for i in (0..n-1).rev() {
        if nums[i] < nums[i+1] {
            right[i] = right[i+1] + nums[i];
        } else {
            right[i] = nums[i];
        }
    }

    let mut max_sum = i64::MIN;

    // Iterate all possible p and q to find the maximum sum
    for p in 1..n-2 {
