            // Check if nums[p..=q] is strictly decreasing
            let mut valid = true;
            for i in p..q {
                if nums[i] <= nums[i+1] {
                    valid = false;
                    break;
                }
            }
            if !valid {
                continue;
            }

            // Find best l < p where nums[l..=p] is strictly increasing
            let mut best_l_sum = i64::MIN;
            for l in 0..p {
                // Check if nums[l..=p] is strictly increasing
                let mut increasing = true;
                for i in l..p {
