                if increasing {
                    let sum = if l == 0 { prefix[p] } else { prefix[p] - prefix[l-1] };
                    if sum > best_l_sum {
                        best_l_sum = sum;
                    }
                }
            }

            // Find best r > q where nums[q..=r] is strictly increasing
            let mut best_r_sum = i64::MIN;
            for r in q+1..n {
                // Check if nums[q..=r] is strictly increasing
                let mut increasing = true;
                for i in q..r {
                    if nums[i] >= nums[i+1] {
                        increasing = false;
                        break;
                    }
                }
                if increasing {
                    let sum = prefix[r] - prefix[q-1];
                    if sum > best_r_sum {
                        best_r_sum = sum;
                    }
                }
            }

            let current_sum = best_l_sum + (prefix[q] - prefix[p-1]) + best_r_sum - nums[p] - nums[q];
            if current_sum > max_sum {
                max_sum = current_sum;
